from decimal import Decimal
from django.db import models
from backend.apps.common.models import BaseModel
from backend.apps.trading.models import TradingAccount,TradingSymbol
class PerformanceAnalytics(BaseModel): account=models.ForeignKey(TradingAccount,on_delete=models.CASCADE,related_name="performance_analytics"); period_start=models.DateTimeField(db_index=True); period_end=models.DateTimeField(db_index=True); win_rate=models.DecimalField(max_digits=6,decimal_places=2,default=Decimal("0")); loss_rate=models.DecimalField(max_digits=6,decimal_places=2,default=Decimal("0")); profit_factor=models.DecimalField(max_digits=12,decimal_places=4,default=Decimal("0")); expectancy=models.DecimalField(max_digits=18,decimal_places=4,default=Decimal("0")); average_rr=models.DecimalField(max_digits=12,decimal_places=4,default=Decimal("0")); average_hold_minutes=models.DecimalField(max_digits=12,decimal_places=2,default=Decimal("0")); max_drawdown=models.DecimalField(max_digits=18,decimal_places=2,default=Decimal("0")); equity_curve=models.JSONField(default=list); daily_profit=models.JSONField(default=dict); weekly_profit=models.JSONField(default=dict); monthly_profit=models.JSONField(default=dict); yearly_profit=models.JSONField(default=dict); trade_distribution=models.JSONField(default=dict); heatmap=models.JSONField(default=dict)
class StrategyStatistic(BaseModel): account=models.ForeignKey(TradingAccount,on_delete=models.CASCADE,related_name="strategy_statistics"); strategy_name=models.CharField(max_length=120,db_index=True); symbol=models.ForeignKey(TradingSymbol,on_delete=models.SET_NULL,null=True,blank=True); total_trades=models.PositiveIntegerField(default=0); wins=models.PositiveIntegerField(default=0); losses=models.PositiveIntegerField(default=0); net_profit=models.DecimalField(max_digits=18,decimal_places=2,default=Decimal("0")); metrics=models.JSONField(default=dict)
class AIAnalysis(BaseModel): account=models.ForeignKey(TradingAccount,on_delete=models.CASCADE,related_name="ai_analyses"); subject=models.CharField(max_length=160,db_index=True); model_name=models.CharField(max_length=120); prompt_hash=models.CharField(max_length=128,db_index=True); input_snapshot=models.JSONField(default=dict); analysis=models.TextField(); confidence=models.DecimalField(max_digits=5,decimal_places=2,default=Decimal("0"))
